9	/// Outcome returned by `Dispatcher::process()` so callers can emit JSONL events.
10	#[derive(Debug)]
11	pub enum DispatchOutcome {
12	    /// A macro matched and fired. `macro_id` and `score` identify which one.
13	    Fired { macro_id: String, score: f32 },
14	    /// No phrase matched above the confidence threshold.
15	    NoMatch,
16	}
