44	/// Receives STT transcripts, finds the best-matching macro phrase, and fires the macro.
45	///
46	/// The dispatcher is shared across threads via `Arc` (see `SAFETY` comments below).
47	/// Live macro registry updates arrive through [`Dispatcher::update_macros`] without
48	/// restarting the pipeline.
49	pub struct Dispatcher {
50	    state: DispatcherState,
51	    matcher: RwLock<PhraseMatcher>,
52	    macros: Arc<RwLock<Vec<MacroConfig>>>,
53	    sound_player: Option<SoundPlayer>,
54	    macro_tx: Sender<MacroCmd>,
55	    default_dwell_ms: u64,
56	    default_gap_ms: u64,
57	}
58	
59	// SAFETY: rodio's OutputStream (held inside SoundPlayer) is !Send, but Dispatcher only ever
60	// accesses sound_player from the single thread that owns it. No reference to sound_player is
61	// shared across threads, so manual Send is sound.
62	unsafe impl Send for Dispatcher {}
63	// SAFETY: same invariant as Send — all access to sound_player is serialised through the single
64	// owning thread; no concurrent access can occur across thread boundaries.
65	unsafe impl Sync for Dispatcher {}
66	
67	impl Dispatcher {
68	    /// Create a new `Dispatcher`.
69	    ///
70	    /// `threshold` is the minimum fuzzy-match score (0.0–1.0) for a phrase to fire.
71	    /// `default_dwell_ms` and `default_gap_ms` are applied to key steps that omit their own timing.
72	    pub fn new(
73	        threshold: f32,
74	        macros: Vec<MacroConfig>,
75	        macro_tx: Sender<MacroCmd>,
76	        default_dwell_ms: u64,
77	        default_gap_ms: u64,
78	    ) -> Self {
79	        let sound_player = match SoundPlayer::new() {
80	            Ok(player) => Some(player),
81	            Err(e) => {
82	                tracing::warn!("Sound player disabled: {}", e);
83	                None
84	            }
85	        };
86	
87	        Self {
88	            state: DispatcherState::new(),
89	            matcher: RwLock::new(PhraseMatcher::new(threshold)),
90	            macros: Arc::new(RwLock::new(macros)),
91	            sound_player,
92	            macro_tx,
93	            default_dwell_ms,
94	            default_gap_ms,
95	        }
96	    }
97	
98	    /// Replace the live macro registry without restarting the pipeline.
99	    pub fn update_macros(&self, new_macros: Vec<MacroConfig>) {
100	        let mut macros = self.macros.write().unwrap();
101	        *macros = new_macros;
102	        tracing::info!("Registry updated with {} macros", macros.len());
103	    }
104	
105	    /// Return the number of macros currently registered.
106	    pub fn macro_count(&self) -> usize {
107	        self.macros.read().unwrap().len()
108	    }
109	
110	    /// Change the phrase-match confidence threshold without rebuilding the pipeline.
111	    ///
112	    /// `threshold` is clamped to `[0.0, 1.0]`; NaN is treated as 0.0.
113	    pub fn update_threshold(&self, threshold: f32) {
114	        let clamped = if threshold.is_nan() {
115	            0.0_f32
116	        } else {
117	            threshold.clamp(0.0, 1.0)
118	        };
119	        let old = self.matcher.read().unwrap().threshold();
120	        *self.matcher.write().unwrap() = PhraseMatcher::new(clamped);
121	        tracing::info!(old, new = clamped, "dispatcher threshold updated");
122	    }
123	
124	    fn check_condition(&self, if_flag: &Option<String>) -> bool {
125	        match if_flag {
126	            None => true,
127	            Some(if_flag) => {
128	                if let Some(stripped) = if_flag.strip_prefix('!') {
129	                    !self.state.get(stripped)
130	                } else {
131	                    self.state.get(if_flag.as_str())
132	                }
133	            }
134	        }
135	    }
136	
137	    /// Match `transcript` against the macro registry and fire the best-scoring macro.
138	    ///
139	    /// Returns [`DispatchOutcome::Fired`] when a phrase matches above the threshold,
140	    /// or [`DispatchOutcome::NoMatch`] otherwise. Side effects: plays an optional
141	    /// sound file and sends a [`MacroCmd`] to the input injector.
142	    pub fn process(&self, transcript: &str) -> DispatchOutcome {
143	        let macros = self.macros.read().unwrap();
144	        let candidates = macros
145	            .iter()
146	            .filter(|m| self.check_condition(&m.if_flag))
147	            .filter_map(|m| m.phrase.as_ref().map(|p| (m.name.as_str(), p.as_str())));
148	
149	        if let Some((best_match_name, score)) = self.matcher.read().unwrap().find_best_match(transcript, candidates) {
150	            tracing::info!(macro_name = best_match_name, score, "Firing macro");
151	            if let Some(mac) = macros.iter().find(|m| m.name == best_match_name) {
152	                if let Some(sound_path) = &mac.sound {
153	                    if let Some(player) = &self.sound_player {
154	                        if let Err(e) = player.play(sound_path) {
155	                            tracing::error!("Failed to play sound for macro {}: {}", mac.name, e);
156	                        }
157	                    }
158	                }
159	
160	                let keys = mac.keys.iter().map(KeyStep::from_config).collect();
161	                let _ = self.macro_tx.send(MacroCmd::Execute {
162	                    keys,
163	                    default_dwell_ms: self.default_dwell_ms,
164	                    default_gap_ms: self.default_gap_ms,
165	                });
166	
167	                if let Some(set_flag) = &mac.set_flag {
168	                    if let Some(stripped) = set_flag.strip_prefix('!') {
169	                        self.state.set(stripped, false);
170	                    } else {
171	                        self.state.set(set_flag.as_str(), true);
172	                    }
173	                }
174	
175	                return DispatchOutcome::Fired {
176	                    macro_id: best_match_name.to_string(),
177	                    score,
178	                };
179	            }
180	        }
181	
182	        tracing::debug!(transcript, "No phrase matched above threshold");
183	        DispatchOutcome::NoMatch
184	    }
185	}
