205	    #[test]
206	    fn test_update_threshold_changes_match_behavior() {
207	        let dispatcher = make_dispatcher(0.99, "eagle airstrike");
208	        // "eagal airstrike" has distance 1 from "eagle airstrike" (15 chars → score ≈ 0.933)
209	        // Should be below threshold 0.99 → NoMatch
210	        assert!(
211	            matches!(dispatcher.process("eagal airstrike"), DispatchOutcome::NoMatch),
212	            "expected NoMatch at threshold 0.99"
213	        );
214	        // Lower threshold to 0.5 → same input should now Fire
215	        dispatcher.update_threshold(0.5);
216	        assert!(
217	            matches!(
218	                dispatcher.process("eagal airstrike"),
219	                DispatchOutcome::Fired { .. }
220	            ),
221	            "expected Fired at threshold 0.5"
222	        );
223	    }
