225	    #[test]
226	    fn test_update_threshold_clamp_negative() {
227	        let dispatcher = make_dispatcher(0.8, "eagle airstrike");
228	        dispatcher.update_threshold(-0.5);
229	        // threshold clamped to 0.0 → everything matches
230	        assert!(matches!(
231	            dispatcher.process("eagle airstrike"),
232	            DispatchOutcome::Fired { .. }
233	        ));
234	    }
