236	    #[test]
237	    fn test_update_threshold_clamp_above_one() {
238	        let dispatcher = make_dispatcher(0.8, "eagle airstrike");
239	        dispatcher.update_threshold(2.0);
240	        // threshold clamped to 1.0 → only exact match fires; "eagal" is not exact
241	        assert!(matches!(
242	            dispatcher.process("eagal airstrike"),
243	            DispatchOutcome::NoMatch
244	        ));
245	        // exact input should still fire (score == 1.0 >= 1.0)
246	        assert!(matches!(
247	            dispatcher.process("eagle airstrike"),
248	            DispatchOutcome::Fired { .. }
249	        ));
250	    }
251	
252	    #[test]
253	    fn test_update_threshold_nan_becomes_zero() {
254	        let dispatcher = make_dispatcher(0.8, "eagle airstrike");
255	        dispatcher.update_threshold(f32::NAN);
256	        // threshold clamped to 0.0 → any non-empty transcript with a candidate matches
257	        assert!(matches!(
258	            dispatcher.process("eagle airstrike"),
259	            DispatchOutcome::Fired { .. }
